<?php
// Composer Autoloader
// This file is auto-generated by Composer

$vendorDir = dirname(__DIR__) . '/vendor';
$baseDir = dirname($vendorDir);

// Load the composer autoloader
if (file_exists($vendorDir . '/autoload.php')) {
    return require $vendorDir . '/autoload.php';
}

// Fallback: load from installed.php
if (file_exists($vendorDir . '/composer/autoload_real.php')) {
    return require $vendorDir . '/composer/autoload_real.php';
}

// If all else fails, load the Composer's installed versions
require_once $vendorDir . '/composer/InstalledVersions.php';

// Simple PSR-4 autoloader for the app
spl_autoload_register(function ($class) use ($baseDir) {
    $prefix = 'App\\';
    $len = strlen($prefix);
    if (strncmp($prefix, $class, $len) !== 0) {
        return;
    }

    $relative_class = substr($class, $len);
    $file = $baseDir . '/app/' . str_replace('\\', '/', $relative_class) . '.php';
    if (file_exists($file)) {
        require $file;
    }
});

// Load Laravel framework
if (file_exists($vendorDir . '/laravel/framework/src/Illuminate/Foundation/helpers.php')) {
    require_once $vendorDir . '/laravel/framework/src/Illuminate/Foundation/helpers.php';
}
